SELECT h.id, h.hazard_type AS hazardType, h.hazard_level AS hazardLevel, h.hazard_source AS hazardSource, h.address, CAST(h.longitude AS CHAR) AS longitude, CAST(h.latitude AS CHAR) AS latitude, h.hazard_desc AS hazardDesc, DATE_FORMAT(h.rectify_start_date, '%Y-%m-%d') AS rectifyStartDate, DATE_FORMAT(h.rectify_end_date, '%Y-%m-%d') AS rectifyEndDate, h.submit_user_name AS submitUserName, DATE_FORMAT(h.submit_time, '%Y-%m-%d %H:%i:%s') AS submitTime, w.name AS assigneeName, h.hazard_photo AS hazardPhoto, h.rectify_status AS rectifyStatus, h.rectify_photo AS rectifyPhoto, h.rectify_video AS rectifyVideo, DATE_FORMAT(h.rectify_time, '%Y-%m-%d %H:%i:%s') AS rectifyTime FROM gas_hazard_info h LEFT JOIN gas_worker w ON h.assignee_id = w.id WHERE h.assignee_id = #{assigneeId}
AND h.rectify_status = #{rectifyStatus}
ORDER BY h.submit_time DESC LIMIT #{start}, #{length}

SELECT COUNT(*)
FROM gas_hazard_info h
WHERE h.assignee_id = #{assigneeId}

    AND h.rectify_status = #{rectifyStatus}
